/* RACC Page Template Styles - Embedded for self-contained functionality */

/* Import Montserrat font */
@import url('https://fonts.googleapis.com/css2?family=Montserrat:ital,wght@0,100..900;1,100..900&display=swap');

/* CSS Variables matching React app exactly */
:root {
  --background: 245 245 245;
  --foreground: 146 64 14;
  --card: 250 250 249;
  --card-foreground: 82 82 91;
  --popover: 250 250 249;
  --popover-foreground: 23 23 23;
  --primary: 202 138 4;
  --primary-foreground: 255 255 255;
  --secondary: 229 229 229;
  --secondary-foreground: 23 23 23;
  --muted: 245 245 245;
  --muted-foreground: 82 82 91;
  --accent: 115 115 115;
  --accent-foreground: 255 255 255;
  --highlight: 234 179 8;
  --highlight-foreground: 202 138 4;
  --destructive: 220 38 38;
  --destructive-foreground: 255 255 255;
  --border: 212 212 212;
  --input: 163 163 163;
  --ring: 82 82 91;
  --radius: 0.5rem;
}

/* Mobile Menu Button Styling */
.racc-mobile-menu-btn {
  background: none !important;
  border: none !important;
  cursor: pointer !important;
  padding: 8px !important;
  color: #374151 !important;
  display: block !important;
  transition: color 0.2s ease !important;
}

.racc-mobile-menu-btn:hover {
  color: #2c5530 !important;
}

@media (min-width: 768px) {
  .racc-mobile-menu-btn {
    display: none !important;
  }
}

/* Mobile Menu Overlay - the section needs these classes */
.racc-mobile-menu-overlay {
  position: fixed !important;
  top: 0 !important;
  left: -100% !important;
  width: 300px !important;
  height: 100vh !important;
  z-index: 10000 !important;
  transition: left 0.3s ease !important;
  box-shadow: 2px 0 10px rgba(0,0,0,0.1) !important;
  overflow-y: auto !important;
  background-color: #ffffff !important;
}

.racc-mobile-menu-overlay.open {
  left: 0 !important;
}

/* Mobile Menu Background Overlay */
.racc-mobile-menu-backdrop {
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100vw !important;
  height: 100vh !important;
  background-color: rgba(0, 0, 0, 0.5) !important;
  z-index: 9999 !important;
  opacity: 0 !important;
  visibility: hidden !important;
  transition: opacity 0.3s ease, visibility 0.3s ease !important;
}

.racc-mobile-menu-backdrop.open {
  opacity: 1 !important;
  visibility: visible !important;
}

/* Mobile Menu Header */
.racc-mobile-header {
  display: flex !important;
  justify-content: space-between !important;
  align-items: center !important;
  padding-bottom: 20px !important;
  border-bottom: 1px solid #e9ecef !important;
}

.racc-mobile-menu-close {
  background: none !important;
  border: none !important;
  cursor: pointer !important;
  padding: 8px !important;
  color: #374151 !important;
  transition: color 0.2s ease !important;
}

.racc-mobile-menu-close:hover {
  color: #2c5530 !important;
}

/* Prevent body scroll when menu is open */
body.mobile-menu-open {
  overflow: hidden !important;
  height: 100vh !important;
}

/* Mobile Navigation Links */
#racc-mobile-nav-placeholder a {
  color: #374151 !important;
  text-decoration: none !important;
  font-weight: 500 !important;
  padding: 0.75rem 0 !important;
  border-bottom: 1px solid #f3f4f6 !important;
  font-size: 18px !important;
  transition: color 0.2s ease !important;
  display: block !important;
}

#racc-mobile-nav-placeholder a:hover {
  color: #2c5530 !important;
}

/* Hide on desktop */
@media (min-width: 768px) {
  .racc-mobile-menu-overlay {
    display: none !important;
  }
  .racc-mobile-menu-backdrop {
    display: none !important;
  }
}

/* Button styles matching React app */
.racc-btn {
  display: inline-flex !important;
  align-items: center !important;
  justify-content: center !important;
  gap: 0.5rem !important;
  white-space: nowrap !important;
  font-size: 0.875rem !important;
  font-weight: 500 !important;
  transition: colors 150ms ease !important;
  padding: 0.375rem 0.75rem !important;
  border-radius: 0.375rem !important;
  text-decoration: none !important;
  cursor: pointer !important;
  border: none !important;
}

.racc-btn:hover {
  text-decoration: none !important;
}

.racc-btn-nominations {
  background-color: rgb(var(--card-foreground)) !important;
  color: rgb(var(--card)) !important;
}

.racc-btn-nominations:hover {
  background-color: rgb(var(--card-foreground) / 0.9) !important;
}

.racc-btn-join {
  background-color: rgb(var(--highlight-foreground)) !important;
  color: rgb(var(--card)) !important;
}

.racc-btn-join:hover {
  background-color: rgb(var(--highlight-foreground) / 0.9) !important;
}

/* RACC Header */
.racc-header {
  background-color: #ffffff !important;
  border-bottom: 1px solid rgb(var(--border)) !important;
  box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1) !important;
}

.racc-nav-menu a {
  text-decoration: none !important;
  color: rgb(var(--foreground)) !important;
  transition: background-color 150ms ease !important;
}

.racc-nav-menu a:hover {
  background-color: rgb(var(--highlight-foreground)) !important;
  color: rgb(var(--card)) !important;
}

/* Footer */
.racc-footer {
  background-color: rgb(var(--card-foreground)) !important;
  color: rgb(var(--card)) !important;
}

.racc-footer a {
  color: inherit !important;
  text-decoration: none !important;
  transition: opacity 150ms ease !important;
}

.racc-footer a:hover {
  opacity: 1 !important;
}

.racc-footer .highlight-link {
  color: rgb(var(--highlight)) !important;
}

.racc-footer .highlight-link:hover {
  color: rgb(var(--highlight-foreground)) !important;
}

/* Remove Divi interference completely */
.et_pb_section {
  padding: 0 !important;
}

.et-main-area {
  background: none !important;
}

#et-main-area,
.et_pb_section,
.et_pb_row {
  padding: 0 !important;
  margin: 0 !important;
  background: none !important;
  min-height: auto !important;
  height: auto !important;
}
